app.Services.GetRequiredService<Microsoft.Extensions.Options.IOptions<Microsoft.Extensions.ML.MLOptions<TicketInput, TicketPrediction>>>()
    .Value.ModelLoader = new Microsoft.Extensions.ML.InMemoryModelLoader(model);

app.MapControllers();
app.Run();

